import sys
from typing import List

class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def hasCycle(self, head: ListNode) -> bool:
        slow = fast = head
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
            if slow == fast:
                return True
        return False

def read_ints():
    return [int(x) for x in sys.stdin.readline().split()]

def read_list():
    return list(map(int, sys.stdin.readline().split()))

def main():
    t = int(sys.stdin.readline())
    for _ in range(t):
        n = int(sys.stdin.readline())
        head = ListNode(0)
        for x in read_list():
            head.next = ListNode(x)
            head = head.next
        head = head.next
        print(Solution().hasCycle(head))

main()

