#include <iostream>
#include <vector>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};

class Solution {
public:
    bool hasCycle(ListNode *head) {
        ListNode *slow = head;
        ListNode *fast = head;
        while (fast && fast->next) {
            slow = slow->next;
            fast = fast->next->next;
            if (slow == fast) return true;
        }
        return false;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        ListNode head(0);
        for (int i = 0; i < n; i++) {
            int x;
            cin >> x;
            ListNode node(x);
            head.next = &node;
            head = head.next;
        }
        head = head.next;
        cout << (Solution().hasCycle(&head) ? '1' : '0') << endl;
    }
    return 0;
}
